import{_ as e,o as t,c as n,j as r,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const u=JSON.parse('{"title":"潜渊囚龙","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/潜渊囚龙.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/潜渊囚龙.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/潜渊囚龙.md"};function l(i,a,b,_,c,p){return t(),n("div",null,[...a[0]||(a[0]=[r("h1",{id:"潜渊囚龙",tabindex:"-1"},[s("潜渊囚龙 "),r("a",{class:"header-anchor",href:"#潜渊囚龙","aria-label":'Permalink to "潜渊囚龙"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"新世短歌037")])])],-1),o('<h1 id="潜渊囚龙-1" tabindex="-1">潜渊囚龙 <a class="header-anchor" href="#潜渊囚龙-1" aria-label="Permalink to &quot;潜渊囚龙&quot;">​</a></h1><p>IDEA-A-113-『潜渊囚龙』<br> 科技本质<br> A+4000<br> 分类：诡镰<br> 武器伤害：28L+2附加<br> 武器特性：【沉重】【双手】【威猛1】【触及3M】<br> 伤害类型：物理-挥砍<br> 体积：5<br> 这是一对异种武器，整个长柄分为多节，中间锁链连接，你可以将其当成巨镰使用，或者消耗一个自由动作将其长柄分成多节，成为诡镰 。<br> 当你想要将诡镰变成巨镰时，你需要消耗一个迅捷动作，控制机关，恢复巨镰。<br> 『潜渊囚龙』是两把诡镰组成的武器，诡镰的末端以虬绕的漆黑锁链相连，传递着暗紫色的深渊光芒，必须双手各持一把才能正常激活异能效果，该武装深渊水晶制成的镰刃会呈暗紫色，庞大的镰身需要使用者具有足够的力量（注：通常以特制外骨骼提供足够的支撑），该武装具有『闭合（clausum）』与『流出（exfluxus）』两种形态，根据形态的不同，该武装内置的定制异能『永世之孽（Angra-Mainyu）』会呈现出不同的力量表现，在下文中将会详细解释具有的能力与对应形态的外观。<br> 需要警告的是，这把武器具有的异灵（Sprite）『潜龙（Ahriman）』的自我认知极不稳定，武装使用者一定要尽全力保证自我意识处于清醒状态，否则后果不堪设想。<br> 『闭合（clausum）』：这是一种将链收合为柄，聚合为巨镰的状态；『闭合』是向内、自闭的形态，通过纠缠在武器上的『永世之孽』进行防御，以该状态进行格挡时，基于格挡防御获得【封闭8】与【反震】特性，反震将造成负能量伤害。<br> 每轮一次，在『闭合』状态下进行全力攻击会立即将巨镰转变为诡镰，进入『流出』状态并立即以诡镰形态进行攻击。<br> 『流出（exfluxus）』：这是一种将柄解放为链，展开为诡镰的状态；『流出』是向外、扩散的形态，通过延伸在武器的上的『永世之孽』进行攻击，在『流出』状态下，诡镰的触及范围将提升至自身的敏感范围，与『闭合』相比，该武装内置的异灵『潜龙』进行同频测试后更为偏向于向外进攻的『流出』状态，如此才能发挥它不断破坏的狂暴本质，只有绝对的掌控力才能完全驾驭这件武装，因祸得福，在『流出』状态下以该武器进行攻击时，一轮一次，可以使这次攻击检定重投一次，取高结算。<br> 除此之外，若在该轮次中，『潜渊囚龙』是由『闭合』状态转变为『流出』，则每次攻击前与攻击后，都可以有一次以自由动作将某一敌人向触及范围内的一点进行拖拽的机会，若在攻击前进行，则需要以擒抱检定进行对抗，若在攻击后进行，则以这次攻击检定出目为dc，敌人以反射豁免；无论是分配在攻击前还是攻击后，切换形态的轮次中，至多可以以此进行4次拖拽。<br> 『永世之孽（Angra-Mainyu）』：处于『闭合』状态时，将基于格挡防御获得4点附加成功与1点全伤害吸收；处于『流出』状态时，攻击将附带等量的A级附身来源精神束缚点数。无论处于何种状态，以『潜渊囚龙』进行的攻击加骰都会提升一级（至多8加骰）。<br> st选开：特殊的，若在持用『潜渊囚龙』时，使用者因任何原因陷入失能（昏迷等未死亡但无法继续战斗的状态），都需要额外进行一次DC为80的意志豁免检定，若这次检定失败，则使用者在死亡前都将被st接管，在表现上，则是被『潜龙（Ahriman）』覆盖自我认知，对接触到的一切生命展开报复性打击，无视敌我地进行无差别攻击。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const f=e(d,[["render",l]]);export{u as __pageData,f as default};
